<script>$(function(){var tiDt=null;function tiInitTable(){if(!$.fn.DataTable)return;if(tiDt){tiDt.destroy();}tiDt=$('#dtb_tax_invoice').DataTable({pageLength:25,order:[[2,'desc']],dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=fin_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','print']}],columnDefs:[{targets:[9],orderable:false,searchable:false},{targets:[5,6],className:'text-right'}]});}$('.input-group.date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});$('.select2').select2({width:'100%',allowClear:true});function initSel(){$('.select2-modal').select2({width:'100%',dropdownParent:$('#ti_modal'),allowClear:true});}function p(){return{tax_direction:'<?=$taxDirection;?>',tax_period:$('#tax_period').val(),status:$('#filter_status').val(),validation_status:$('#filter_validation').val()};}function load(){if(tiDt){tiDt.destroy();tiDt=null;}$('#ti_body').html('<tr><td colspan="10" class="text-center">Loading...</td></tr>');$.post('<?=base_admin();?>modul/<?=$modulePath;?>/tax_invoice_action.php?act=filter',p(),function(r){if(r.status==='success'){$('#ti_body').html(r.html);$('#kpi_dpp').text(r.dpp);$('#kpi_vat').text(r.vat);$('#kpi_count').text(r.count);tiInitTable();}else $('#ti_body').html('<tr><td colspan="10" class="text-danger text-center">'+r.message+'</td></tr>');},'json');}$('#btn_filter').on('click',load);$('#btn_add').on('click',function(){$('#ti_form')[0].reset();$('#id').val('');$('#tax_invoice_date').val('<?=date('Y-m-d');?>');$('#form_tax_period').val($('#tax_period').val());$('#source_module').val('<?=$taxDirection==='IN'?'VENDOR_INVOICE':'SALES_INVOICE';?>');$('#currency').val('IDR');$('#ti_modal').modal('show');initSel();});$('#tax_code_id').on('change',function(){var rate=parseFloat($(this).find(':selected').data('rate')||0),dpp=parseFloat($('#dpp_amount').val()||0);if(rate>0)$('#vat_amount').val((dpp*rate/100).toFixed(2));});$('#dpp_amount').on('keyup change',function(){$('#tax_code_id').trigger('change');});$(document).on('click','.ti-save',function(){var act=$(this).data('act');$.post('<?=base_admin();?>modul/<?=$modulePath;?>/tax_invoice_action.php?act='+act,$('#ti_form').serialize(),function(r){if(r.status==='success'){Swal.fire('Berhasil',r.message,'success');$('#ti_modal').modal('hide');load();}else Swal.fire('Gagal',r.message,'error');},'json');});$(document).on('click','.ti-detail',function(){var b=$(this);$('#tax_invoice_detail_body').html('<div class="table-responsive"><table class="table table-bordered table-striped"><tr><th style="width:180px">Tax Invoice</th><td>'+b.data('no')+'</td></tr><tr><th>Date / Period</th><td>'+b.data('date')+' / '+$('#tax_period').val()+'</td></tr><tr><th>Partner</th><td>'+b.data('partner')+'</td></tr><tr><th>Source</th><td>'+b.data('source')+'</td></tr><tr><th>DPP</th><td class="text-right">'+b.data('dpp')+'</td></tr><tr><th><?=fin_h('finance_vat', 'VAT');?></th><td class="text-right">'+b.data('vat')+'</td></tr><tr><th><?=fin_h('common_status', 'Status');?></th><td>'+b.data('status')+'</td></tr><tr><th>Validation</th><td>'+b.data('validation')+'</td></tr></table></div>');$('#modal_tax_invoice_detail').modal('show');});$(document).on('click','.ti-post',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/<?=$modulePath;?>/tax_invoice_action.php?act=post',{id:id,tax_direction:'<?=$taxDirection;?>'},function(r){r.status==='success'?Swal.fire('Berhasil',r.message,'success'):Swal.fire('Gagal',r.message,'error');load();},'json');});$(document).on('click','.ti-cancel',function(){var id=$(this).data('id');Swal.fire({title:'Cancel tax invoice?',icon:'warning',showCancelButton:true}).then(function(x){if(x.isConfirmed){$.post('<?=base_admin();?>modul/<?=$modulePath;?>/tax_invoice_action.php?act=cancel',{id:id},function(r){r.status==='success'?Swal.fire('Berhasil',r.message,'success'):Swal.fire('Gagal',r.message,'error');load();},'json');}});});$('#btn_excel').on('click',function(){window.open('<?=base_admin();?>modul/<?=$modulePath;?>/tax_invoice_action.php?act=excel&'+$.param(p()));});load();});</script>
